$dest = "C:\Users\Elite\OneDrive\Documents\websites\Sr renovations LLC\public\portfolio"
$ua = "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36"

foreach ($item in $urls) {
  $out = Join-Path $dest "$($item.id).jpg"
  try {
    Invoke-WebRequest -Uri $item.url -OutFile $out -UseBasicParsing -UserAgent $ua -ErrorAction Stop
    $size = (Get-Item $out).Length
    Write-Host "OK   $($item.id).jpg  ($size bytes)"
  } catch {
    Write-Host "FAIL $($item.id).jpg  -- $($_.Exception.Message)"
  }
}

Write-Host ""
Write-Host "==== Final contents ===="
Get-ChildItem $dest | Format-Table Name, Length -AutoSize
